namespace sv_c5a95c9afa60408d84bbde61a20bc252.Services;

/// <summary>
/// Scoped service that tracks the currently selected warehouse for a single circuit.
/// Components subscribe to <see cref="OnChange"/> to re-render when the selection changes.
/// </summary>
public class WarehouseState
{
    public string SelectedWarehouseId { get; private set; } = "WH-1";
    public string SelectedWarehouseName => Warehouses
        .FirstOrDefault(w => w.Id == SelectedWarehouseId)?.Name ?? "Unknown";

    public static readonly IReadOnlyList<Warehouse> Warehouses =
    [
        new("WH-1", "Warehouse A – East"),
        new("WH-2", "Warehouse B – West"),
        new("WH-3", "Warehouse C – Central"),
    ];

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId) return;
        SelectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public record Warehouse(string Id, string Name);

namespace sv_c5a95c9afa60408d84bbde61a20bc252.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts and notifies all subscribers.
/// Each circuit (user) gets its own instance, so alert counts are independent.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private readonly Lock _lock = new();

    public int CurrentLowStockCount { get; private set; }

    /// <summary>
    /// Fired from a background thread whenever new alert data arrives.
    /// Subscribers must wrap StateHasChanged in InvokeAsync.
    /// </summary>
    public event Action? OnAlertDataChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulates a database query
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component that needs polling becomes active.
    /// Polling starts on the first subscriber and stops when the last unsubscribes.
    /// </summary>
    public void StartPolling()
    {
        lock (_lock)
        {
            _subscriberCount++;
            if (_subscriberCount == 1)
            {
                _cts = new CancellationTokenSource();
                _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
                _ = PollLoopAsync(_cts.Token);
            }
        }
    }

    public void StopPolling()
    {
        lock (_lock)
        {
            _subscriberCount = Math.Max(0, _subscriberCount - 1);
            if (_subscriberCount == 0)
            {
                _cts?.Cancel();
                _timer?.Dispose();
                _timer = null;
            }
        }
    }

    /// <summary>
    /// Forces an immediate refresh — used when the warehouse changes while polling is active.
    /// </summary>
    public async Task RefreshAsync()
    {
        CurrentLowStockCount = await GetLowStockCountAsync(_warehouseState.SelectedWarehouseId);
        OnAlertDataChanged?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire immediately on first subscribe so the UI isn't stale
        await RefreshAsync();

        while (_timer is not null)
        {
            try
            {
                if (!await _timer.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            CurrentLowStockCount = await GetLowStockCountAsync(
                _warehouseState.SelectedWarehouseId);
            OnAlertDataChanged?.Invoke();
        }
    }

    private async void OnWarehouseChanged()
    {
        // When the warehouse changes, immediately refresh if we're polling
        if (_subscriberCount > 0)
        {
            await RefreshAsync();
        }
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _timer?.Dispose();
    }
}

