@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@implements IDisposable

<select class="form-select form-select-sm"
        style="max-width: 220px;"
        value="@WarehouseState.SelectedWarehouseId"
        @onchange="OnWarehouseSelected">
    @foreach (var wh in sv_c5a95c9afa60408d84bbde61a20bc252.Services.WarehouseState.Warehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private void OnWarehouseSelected(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _handler;
    }

    public void Dispose() => WarehouseState.OnChange -= _handler;
}

